CHAPTERS = [
 {"slug":"ch01-nao-tente","sub":"CAPÍTULO 1: Não Tente",
  "intro":"Quanto mais você corre atrás de se sentir bem, pior se sente. A sutil arte não é não ligar para nada — é gastar sua cota finita de preocupação só no que importa e aceitar de bom grado o resto.",
  "cards":[
      {"ic":"gap","t":"A Cota de Fodas-se","emph":"Cota","b":"Você só tem uma quantidade <strong>finita</strong> de fodas-se para dar na vida — espalhá-los em tudo é falir aos poucos, esgotado por coisas que nunca mereceram. “Não ligar” não é ser frio nem blasé: é o luxo brutal de reservar o pouco que você tem para o que de fato conta. Quem se importa com tudo acaba sem se importar com nada — só vibra de ansiedade por causa do ruído alheio.","tip":"<strong>Como aplicar:</strong> antes de reagir, pergunte “isto merece um dos meus poucos fodas-se?”. Spoiler: quase nunca merece."},
      {"ic":"spiral","t":"O Feedback Loop do Inferno","emph":"do Inferno","b":"Você se sente mal — e então se sente mal <strong>por</strong> se sentir mal, ansioso por estar ansioso, culpado por estar triste. A obsessão de só sentir coisa boa é a própria fábrica de coisa ruim: cada “eu não deveria estar sentindo isso” acende a camada de cima. O inimigo nunca foi a emoção ruim; é a guerra que você declara contra ela.","tip":"<strong>Sinal de alerta:</strong> “pensar positivo” à força é jogar gasolina no incêndio — é a recusa de sentir que prende.","warn":True},
      {"ic":"leaf","t":"Aceitar em vez de Lutar","emph":"Aceitar","b":"A saída não é mais positividade — é largar a briga. Quando você admite “tudo bem estar ansioso agora”, tira da ansiedade o único combustível que ela tinha: a sua resistência. Manson vira a chave de ponta-cabeça — <strong>querer a experiência ruim já é, em si, uma experiência boa</strong>. A dor aceita atravessa e vai embora; a dor negada faz as malas e se muda pra dentro de você.","tip":"<strong>Regra:</strong> diga “tudo bem sentir isto agora” — aceitar é o que corta o combustível da emoção."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 1",
  "lessons":["Escolha as poucas coisas que merecem seus fodas-se; o resto, deixa.","Pare de brigar com a emoção ruim — a briga é que a mantém.","Importar-se com tudo é o mesmo que não se importar com nada."]},

 {"slug":"ch02-felicidade-problema","sub":"CAPÍTULO 2: A Felicidade é um Problema",
  "intro":"Felicidade não é um lugar sem problemas onde você finalmente descansa — ela mora dentro do ato de resolvê-los. A vida é uma fila infinita de problemas; a meta nunca foi zerá-la, é conseguir problemas melhores.",
  "cards":[
      {"ic":"mountain","t":"Felicidade é Resolver Problemas","emph":"Resolver","b":"Felicidade não é uma praia onde você chega e estica a toalha — é o trabalho de <strong>resolver problemas</strong>. A vida entrega uma fila infinita deles: resolver um só te promove ao próximo. “Sem problemas” não existe como estado; existe trocar problemas ruins por problemas melhores. Quem nega a fila adoece; quem aceita, anda.","tip":"<strong>Modelo mental:</strong> a meta nunca foi zerar problemas — é merecer problemas melhores."},
      {"ic":"key","t":"Que Dor Você Sustenta?","emph":"Que Dor","b":"A pergunta de sempre — “o que você quer?” — não decide porcaria nenhuma: todo mundo quer abdômen, grana e amor. A que separa de fato uma vida da outra é “<strong>que dor você aguenta sustentar?</strong>”. Você quer o corpo, mas quer a fome e a academia às seis da manhã? Não é o sonho que define onde você chega, é o sofrimento que você aceita pagar por ele.","tip":"<strong>Como aplicar:</strong> antes de cobrar o prêmio, olhe o processo que dói — é ele, não o prêmio, que você vai viver todo dia.","wide":True},
      {"ic":"target","t":"A Dor que Constrói","emph":"Constrói","b":"Tem dor que apodrece e tem dor que constrói. A dor <strong>escolhida</strong> — o treino, o estudo, a conversa difícil, o vínculo que cobra — vira músculo, ofício e profundidade. A dor evitada não evapora: ela se acumula em ansiedade e ressentimento represado. O prazer mente sobre a conta; a dor certa é a única bússola que fala a verdade.","tip":"<strong>Regra:</strong> escolha a luta que vale — porque a opção “sem luta nenhuma” não está no cardápio."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 2",
  "lessons":["Pergunte que dor você aceita sustentar, não só o que você quer.","Mire problemas melhores — não a fantasia de não ter problema.","A dor com significado constrói; a dor evitada se acumula."]},

 {"slug":"ch03-voce-nao-e-especial","sub":"CAPÍTULO 3: Você Não é Especial",
  "intro":"Acreditar que você merece se sentir bem o tempo todo — ou que nasceu para coisas extraordinárias — é doença, não combustível. A verdade impopular é que aceitar-se mediano em quase tudo é o que liberta.",
  "cards":[
      {"ic":"mask","t":"A Tirania do Excepcionalismo","emph":"Excepcionalismo","b":"Te criaram repetindo que você é especial, destinado à grandeza — e essa promessa é uma armadilha. Quando todo mundo precisa ser extraordinário, a vida comum (que é 99% da vida) vira fracasso permanente. A expectativa inflada não liga motor nenhum: só garante <strong>frustração crônica</strong> diante de uma realidade que não leu o seu roteiro.","tip":"<strong>Sinal de alerta:</strong> exigir-se especial o tempo todo é assinar contrato com a decepção — quanto maior a expectativa, mais certo o tombo.","warn":True},
      {"ic":"eye","t":"As Duas Faces do Direito","emph":"Duas Faces","b":"Achar que você tem direito a tudo veste duas máscaras opostas. “<strong>Eu sou melhor que todo mundo</strong>” e “<strong>eu sou o mais ferrado do planeta</strong>” parecem inimigas, mas são gêmeas: as duas te plantam no centro do universo e fogem do comum. A vítima profissional e o gênio incompreendido têm exatamente a mesma doença — um ego que se recusa a ser só mais um.","tip":"<strong>Modelo mental:</strong> humildade realista — “sou mediano em quase tudo” — é mais forte que qualquer autoestima inflada."},
      {"ic":"scale","t":"Mediano, e Tudo Bem","emph":"Tudo Bem","b":"A verdade que liberta é dura de engolir: quase tudo que você faz vai ser comum, e tudo bem. Aceitar a própria mediania <strong>devolve toda a energia que você gastava provando grandeza</strong> e a aponta para o pouco que de fato importa. Quem solta o “eu mereço” começa, erra, melhora — e é justamente por isso que, de vez em quando, faz algo grande de verdade.","tip":"<strong>Regra:</strong> aceite ser comum no quase-tudo e concentre o esforço no pouco que dá significado."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 3",
  "lessons":["Largue a exigência de ser especial — ela só te garante frustração.","Sentir-se acima ou abaixo de todos é o mesmo ego centrando o mundo em você.","Aceitar a própria mediania libera energia para o que importa."]},

 {"slug":"ch04-valores","sub":"CAPÍTULO 4: Os Valores",
  "intro":"Tudo na sua vida é medido por valores — as réguas com que você decide o que conta como vitória. E trocar a régua errada pela certa é, literalmente, a mudança que muda tudo.",
  "cards":[
      {"ic":"scale","t":"Maus vs Bons Valores","emph":"Bons Valores","b":"Toda vida roda sobre uma régua, queira você ou não. <strong>Maus valores</strong> (prazer, status, estar sempre certo, parecer positivo) são externos, fora do seu controle e sem linha de chegada: você nunca chega. <strong>Bons valores</strong> (honestidade, curiosidade, humildade) são reais, construtivos e seus — pagos com o seu esforço, não com a aprovação dos outros.","tip":"<strong>Como aplicar:</strong> prefira a régua que depende de você (esforço, honestidade) à que depende dos outros (aprovação, dinheiro, resultado).","wide":True},
      {"ic":"pivot","t":"Controle a Métrica, não o Fim","emph":"a Métrica","b":"Você não controla o resultado — controla os valores pelos quais escolhe que problemas vale a pena ter. O mesmo fato vira triunfo ou tragédia conforme a régua que o mede: bons valores te fazem <strong>sofrer pelas coisas certas</strong>. Mexer na métrica é a única alavanca de verdade, porque é a única coisa que está, do começo ao fim, nas suas mãos.","tip":"<strong>Modelo mental:</strong> você não escolhe o placar — escolhe qual jogo está sendo pontuado."},
      {"ic":"target","t":"Mude a Régua, Muda a Vida","emph":"Muda a Vida","b":"Dois vendedores: um se mede por “fechar todo negócio” — não depende só dele, então vive frustrado e roendo as unhas; o outro por “ser honesto e melhorar a cada ligação” — depende dele, então dorme em paz e, no fim das contas, vende mais. <strong>Mesma profissão, vidas opostas — só mudou a régua.</strong> Descubra qual régua você usa hoje e, então, troque-a.","tip":"<strong>Regra:</strong> escreva os 3 valores pelos quais você se julga hoje — e conte quantos dependem realmente de você."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 4",
  "lessons":["Descubra a régua pela qual você se mede hoje.","Troque valores externos (aprovação, status) por valores que dependem de você.","Mude a métrica e a vida muda junto."]},

 {"slug":"ch05-responsabilidade","sub":"CAPÍTULO 5: Você Está Sempre Escolhendo",
  "intro":"Você pode não ter culpa nenhuma do que te aconteceu, mas é sempre responsável pelo que faz com isso. Confundir as duas coisas é exatamente o que mantém tanta gente presa.",
  "cards":[
      {"ic":"key","t":"Responsabilidade ≠ Culpa","emph":"Culpa","b":"As duas vivem se misturando, e a mistura aprisiona. <strong>Culpa</strong> olha para trás: de quem foi o erro? <strong>Responsabilidade</strong> olha para agora: o que eu faço com isso? Você pode não ter culpa alguma do que te jogaram no colo — e ainda assim a resposta é 100% sua. Assumir o que você não causou não é injustiça: é a única forma de reaver o controle.","tip":"<strong>Como aplicar:</strong> troque a pergunta “de quem é a culpa?” por “qual é a minha resposta?”.","wide":True},
      {"ic":"pivot","t":"Você Está Sempre Escolhendo","emph":"Sempre Escolhendo","b":"Não existe ficar em cima do muro. “Não reagir”, “deixar pra lá”, “esperar passar” também são respostas que você escolheu — só que fingindo que não escolheu. O acontecimento não é a sua arena; a <strong>reação sempre é</strong>. Toda vez que você diz “eu não tive escolha”, você teve — só terceirizou a decisão para o medo, o hábito ou os outros.","tip":"<strong>Modelo mental:</strong> sua arena nunca é o que aconteceu — é o que você faz com o que aconteceu."},
      {"ic":"eye","t":"O Conforto do Vitimismo","emph":"Vitimismo","b":"Jogar a culpa no mundo dá um alívio imediato e viciante — “não sou eu, são eles”. Só que é empréstimo a juros de agiota: <strong>quem entrega a culpa ao mundo entrega ao mundo o controle</strong>, e fica de mãos atadas para mudar qualquer coisa. O “a culpa é deles” conforta hoje e te acorrenta amanhã, até virar uma identidade inteira de impotência.","tip":"<strong>Sinal de alerta:</strong> quando “a culpa é deles” vira a sua personalidade, você trocou poder por desculpa.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 5",
  "lessons":["Separe culpa (passado) de responsabilidade (presente).","Assuma a resposta como sua, mesmo sem ter causado o problema.","O vitimismo conforta hoje e te deixa impotente amanhã."]},

 {"slug":"ch06-duvida","sub":"CAPÍTULO 6: Você Está Errado Sobre Tudo",
  "intro":"A certeza é inimiga do crescimento; a dúvida é o motor dele. Quanto mais frouxo você segura suas crenças e sua identidade, mais espaço sobra para você mudar.",
  "cards":[
      {"ic":"lens","t":"Crescer é Estar Menos Errado","emph":"Menos Errado","b":"Toda crença que você carrega hoje é <strong>rascunho</strong> — uma versão que o tempo ainda vai corrigir. A meta nunca foi “acertar de uma vez e fechar o assunto”; é estar um pouco menos errado a cada ano. A certeza é confortável e estéril; a dúvida incomoda e fecunda. Quem exige estar certo agora paga o preço de não melhorar depois.","tip":"<strong>Como aplicar:</strong> antes de cravar sua posição, pergunte “e se eu estiver errado sobre isto?” — e leve a sério, não como formalidade."},
      {"ic":"mask","t":"A Lei da Evitação","emph":"Evitação","b":"A Lei da Evitação de Manson: quanto mais algo ameaça a sua <strong>identidade</strong>, mais você foge dele — e nem percebe que está fugindo. Quem se define como “o especialista” evita toda situação onde poderia parecer ignorante, e trava de aprender justo onde mais precisava. A identidade inflada é a mais frágil de todas: qualquer arranhão vira fuga disfarçada de “não tenho interesse nisso”.","tip":"<strong>Sinal de alerta:</strong> aquilo que você evita olhar “porque não vale a pena” costuma ser exatamente o que ameaça a sua imagem.","warn":True},
      {"ic":"leaf","t":"Segure a Identidade Leve","emph":"Leve","b":"A saída é se definir de forma <strong>ampla e leve</strong>: “sou alguém que aprende”, “sou curioso”, no lugar de “sou o melhor em X”. Uma identidade larga te deixa trocar de carreira, de opinião e de hábito sem sentir que está morrendo por dentro. Matar as próprias certezas não é se perder — é abrir a porta para quem você ainda pode virar.","tip":"<strong>Regra:</strong> quanto mais leve a etiqueta que você cola em si, mais livre você fica para mudar de ideia."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 6",
  "lessons":["Segure crenças e identidade de forma leve — são rascunho, não pedra.","Pergunte \"e se eu estiver errado?\" antes de cravar uma posição.","O que você evita olhar costuma ser o que ameaça a sua imagem."]},

 {"slug":"ch07-faca-algo","sub":"CAPÍTULO 7: O Fracasso é o Caminho",
  "intro":"Pare de esperar motivação para agir; aja, e a motivação aparece depois. O fracasso não é o muro que bloqueia o caminho — ele é o próprio caminho.",
  "cards":[
      {"ic":"spark","t":"O Ciclo Invertido","emph":"Invertido","b":"O senso comum manda esperar: inspiração → motivação → ação. É por isso que você fica travado — de braços cruzados, esperando uma vontade que nunca bate à porta. Manson inverte a ordem: <strong>ação → inspiração → motivação</strong>. Você não age porque está motivado; fica motivado porque começou. O movimento, mesmo torto e a contragosto, acende o combustível que você jurava precisar antes de começar.","tip":"<strong>Como aplicar:</strong> travado? faça a menor ação possível agora mesmo — é ela que destrava a próxima.","wide":True},
      {"ic":"mountain","t":"O Fracasso é o Caminho","emph":"o Caminho","b":"O fracasso não é o muro que fecha a estrada — ele <strong>é</strong> a estrada. A ação errada te ensina algo concreto; a inércia cautelosa não ensina rigorosamente nada. Quem trata o erro como sentença final paralisa; quem trata como informação avança. Cada tropeço é um dado a mais te aproximando da resposta — e errar para a frente bate ficar parado de medo, todas as vezes.","tip":"<strong>Modelo mental:</strong> errar é caro; não errar nada por medo é mais caro ainda — só que a conta vem invisível."},
      {"ic":"pivot","t":"Faça Algo","emph":"Algo","b":"Contra a paralisia, o atalho cabe em duas palavras: <strong>faça algo</strong>. Não a coisa certa, não a coisa perfeita — qualquer coisinha. Escreva a frase ruim, mande o e-mail tosco, dê o primeiro passo torto. A primeira ação minúscula quebra a inércia e gera justo o impulso que você esperava receber da motivação. A ação fácil sempre ganha da espera pela vontade.","tip":"<strong>Regra:</strong> motivação é consequência da ação, nunca pré-requisito dela."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 7",
  "lessons":["Aja primeiro; a motivação vem na carona da ação, não antes.","Trate o fracasso como informação, nunca como sentença.","Faça a menor coisa possível para quebrar a paralisia."]},

 {"slug":"ch08-nao-e-morte","sub":"CAPÍTULO 8: O Não e a Morte",
  "intro":"Significado não nasce de manter todas as portas abertas — nasce de escolher uma e fechar as outras. E a bússola final, a que corta o supérfluo sem dó, é encarar a sua própria morte.",
  "cards":[
      {"ic":"link","t":"Comprometer-se é Rejeitar","emph":"Rejeitar","b":"Dizer sim a uma coisa é dizer não a mil — e é exatamente essa <strong>rejeição</strong> que dá peso ao que sobra. A liberdade ilimitada de deixar tudo em aberto tem cara de riqueza, mas é oca: sem fronteiras, nada vale nada. O compromisso não te tira opções como castigo; ele concentra a sua vida num ponto fundo em vez de espalhá-la rasa por toda parte.","tip":"<strong>Como aplicar:</strong> profundidade &gt; amplitude — escolha uma coisa a fundo em vez de colecionar inícios rasos.","wide":True},
      {"ic":"scale","t":"Profundidade > Amplitude","emph":"Profundidade","b":"Quem nunca se compromete — com ninguém, nenhum projeto, nenhuma cidade — termina com uma gaveta cheia de começos rasos. Uma relação, um ofício, um lugar escolhidos a fundo valem mais que infinitas possibilidades nunca tocadas. <strong>É o “não” às alternativas que dá sentido ao “sim”.</strong> O medo de perder qualquer coisa faz você não viver coisa nenhuma.","tip":"<strong>Modelo mental:</strong> manter tudo em aberto não é guardar opções — é não chegar a lugar nenhum."},
      {"ic":"clock","t":"A Morte como Bússola","emph":"como Bússola","b":"A bússola final, a que corta o supérfluo sem pedir licença, é encarar a própria morte. Lembrar que você vai morrer — <strong>memento mori</strong> — faz o trivial despencar sozinho e revela o pouquíssimo que de fato merece os seus poucos fodas-se. A finitude não é a sombra que pesa sobre a vida: é a luz que mostra o que nela tem valor. Encurtar a vida na cabeça é o que alonga o que importa.","tip":"<strong>Regra:</strong> use a finitude como filtro — “se eu morresse em breve, isto ainda mereceria o meu tempo?”."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 8",
  "lessons":["Comprometa-se: é o não às alternativas que dá significado ao sim.","Use a sua finitude como filtro do que merece atenção.","Uma coisa a fundo vale mais que mil possibilidades intocadas."]},
]
